  1	import {
  2	  FormGroup,
  3	  FormSelect,
  4	  FormSelectOption,
  5	  Modal,
  6	  TextInput,
  7	  Wizard,
  8	  WizardStep,
  9	} from '@patternfly/react-core';
 10	import * as React from 'react';
 11	import { LimitConfig } from './types';
 12	import { useTranslation } from 'react-i18next';
 13	
 14	const LimitConfigForm: React.FC<{
 15	  newLimit: LimitConfig;
 16	  setNewLimit: (limit: LimitConfig) => void;
 17	  rateName: string;
 18	  setRateName: (name: string) => void;
 19	}> = ({ newLimit, setNewLimit, rateName, setRateName }) => {
 20	  const { t } = useTranslation('plugin__kuadrant-console-plugin');
 21	  return (
 22	    <>
 23	      <FormGroup label={t('Limit Name')} fieldId="limit-name">
 24	        <TextInput
 25	          value={rateName}
 26	          onChange={(event) => setRateName(event.currentTarget.value)}
 27	          isRequired
 28	        />
 29	      </FormGroup>
 30	      <FormGroup label={t('Limit')} fieldId="limit">
 31	        <TextInput
 32	          type="number"
 33	          value={newLimit.rates?.[0]?.limit || ''}
 34	          onChange={(event) =>
 35	            setNewLimit({
 36	              ...newLimit,
 37	              rates: [{ ...newLimit.rates?.[0], limit: parseInt(event.currentTarget.value, 10) }],
 38	            })
 39	          }
 40	          isRequired
 41	        />
 42	      </FormGroup>
 43	      <FormGroup label={t('Duration')} fieldId="duration">
 44	        <TextInput
 45	          type="number"
 46	          value={newLimit.rates?.[0]?.duration || ''}
 47	          onChange={(event) =>
 48	            setNewLimit({
 49	              ...newLimit,
 50	              rates: [
 51	                { ...newLimit.rates?.[0], duration: parseInt(event.currentTarget.value, 10) },
 52	              ],
 53	            })
 54	          }
 55	          isRequired
 56	        />
 57	      </FormGroup>
 58	      <FormGroup label={t('Unit')} fieldId="unit">
 59	        <FormSelect
 60	          value={newLimit.rates?.[0]?.unit || 'second'}
 61	          onChange={(event) =>
 62	            setNewLimit({
 63	              ...newLimit,
 64	              rates: [
 65	                {
 66	                  ...newLimit.rates?.[0],
 67	                  unit: event.currentTarget.value as 'second' | 'minute' | 'hour' | 'day',
 68	                },
 69	              ],
 70	            })
 71	          }
 72	        >
 73	          <FormSelectOption value="second" label="Second" />
 74	          <FormSelectOption value="minute" label="Minute" />
 75	          <FormSelectOption value="hour" label="Hour" />
 76	          <FormSelectOption value="day" label="Day" />
 77	        </FormSelect>
 78	      </FormGroup>
 79	    </>
 80	  );
 81	};
 82	
 83	const AddLimitModal: React.FC<{
 84	  isOpen: boolean;
 85	  onClose: () => void;
 86	  newLimit: LimitConfig;
 87	  setNewLimit: (limit: LimitConfig) => void;
 88	  rateName: string;
 89	  setRateName: (name: string) => void;
 90	  handleSave: () => void;
 91	}> = ({ isOpen, onClose, newLimit, setNewLimit, rateName, setRateName, handleSave }) => {
 92	  const { t } = useTranslation('plugin__kuadrant-console-plugin');
 93	  return (
 94	    <Modal isOpen={isOpen} onClose={onClose} title={t('Add Limit')} width="50%">
 95	      <div className="kuadrant-modal-dynamic-height">
 96	        <Wizard height={400} onSave={handleSave} onClose={onClose}>
 97	          <WizardStep
 98	            name={t('Define Rate Limit')}
 99	            id="define-rate-limit"
100	            footer={{ nextButtonText: t('Add Limit'), isBackHidden: true }}
101	          >
102	            <LimitConfigForm
103	              newLimit={newLimit}
104	              setNewLimit={setNewLimit}
105	              rateName={rateName}
106	              setRateName={setRateName}
107	            />
108	          </WizardStep>
109	        </Wizard>
110	      </div>
111	    </Modal>
112	  );
113	};
114	
115	export default AddLimitModal;

